20	
21	template<typename T>
22	void Decoder<T>::initialize()
23	{
24	    self_attention_layer_ = new DecoderSelfAttentionLayer<T>(max_batch_size_,
25	                                                             head_num_,
26	                                                             size_per_head_,
27	                                                             stream_,
28	                                                             cublas_wrapper_,
29	                                                             allocator_,
30	                                                             is_free_buffer_after_forward_);
31	
32	    cross_attention_layer_ = new DecoderCrossAttentionLayer<T>(max_batch_size_,
33	                                                               head_num_,
34	                                                               size_per_head_,
35	                                                               stream_,
36	                                                               cublas_wrapper_,
37	                                                               allocator_,
38	                                                               is_free_buffer_after_forward_);
39	
40	    ffn_layer_ = new ReluFfnLayer<T>(max_batch_size_,
41	                                     1,
42	                                     head_num_,
43	                                     size_per_head_,
44	                                     0,  // expert_num
45	                                     inter_size_,
46	                                     stream_,
47	                                     cublas_wrapper_,
48	                                     allocator_,
49	                                     is_free_buffer_after_forward_);
50	}
51	
52	template<typename T>
53	void Decoder<T>::allocateBuffer()
54	{
55	    if (is_allocate_buffer_ == false) {
56	        decoder_normed_input_ = reinterpret_cast<T*>(
57	            allocator_->reMalloc(decoder_normed_input_, sizeof(T) * max_batch_size_ * hidden_units_, false));
58	        self_attn_output_ = reinterpret_cast<T*>(
59	            allocator_->reMalloc(self_attn_output_, sizeof(T) * max_batch_size_ * hidden_units_, false));
60	        normed_self_attn_output_ = reinterpret_cast<T*>(
61	            allocator_->reMalloc(normed_self_attn_output_, sizeof(T) * max_batch_size_ * hidden_units_, false));
62	        cross_attn_output_ = reinterpret_cast<T*>(
63	            allocator_->reMalloc(cross_attn_output_, sizeof(T) * max_batch_size_ * hidden_units_, false));
64	        normed_cross_attn_output_ = reinterpret_cast<T*>(
65	            allocator_->reMalloc(normed_cross_attn_output_, sizeof(T) * max_batch_size_ * hidden_units_, false));
66	        decoder_layer_output_ = reinterpret_cast<T*>(
67	            allocator_->reMalloc(decoder_layer_output_, sizeof(T) * max_batch_size_ * hidden_units_, false));
68	        is_allocate_buffer_ = true;
69	    }
70	}
71	
72	template<typename T>
73	void Decoder<T>::allocateBuffer(size_t batch_size)
74	{
75	    if (is_allocate_buffer_ == false) {
76	        decoder_normed_input_ = reinterpret_cast<T*>(
77	            allocator_->reMalloc(decoder_normed_input_, sizeof(T) * batch_size * hidden_units_, false));
78	        self_attn_output_ = reinterpret_cast<T*>(
79	            allocator_->reMalloc(self_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
80	        normed_self_attn_output_ = reinterpret_cast<T*>(
81	            allocator_->reMalloc(normed_self_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
82	        cross_attn_output_ = reinterpret_cast<T*>(
83	            allocator_->reMalloc(cross_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
84	        normed_cross_attn_output_ = reinterpret_cast<T*>(
85	            allocator_->reMalloc(normed_cross_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
86	        decoder_layer_output_ = reinterpret_cast<T*>(
87	            allocator_->reMalloc(decoder_layer_output_, sizeof(T) * batch_size * hidden_units_, false));
88	        is_allocate_buffer_ = true;
89	    }
90	}
91	
92	template<typename T>
93	void Decoder<T>::freeBuffer()
94	{
95	    allocator_->free((void**)(&decoder_normed_input_));
96	    allocator_->free((void**)(&self_attn_output_));
97	    allocator_->free((void**)(&normed_self_attn_output_));
98	    allocator_->free((void**)(&cross_attn_output_));
99	    allocator_->free((void**)(&normed_cross_attn_output_));
100	    allocator_->free((void**)(&decoder_layer_output_));
101	}
102	
103	template<typename T>
104	bool Decoder<T>::isValidBatchSize(size_t batch_size)
105	{
106	    if (max_batch_size_ == 0) {
107	        max_batch_size_ = batch_size;
108	        return true;
109	    }
110	    else {
111	        return batch_size <= max_batch_size_;
112	    }
113	}
114	
115	template<typename T>
116	Decoder<T>::Decoder(size_t           max_batch_size,
117	                    size_t           head_num,
118	                    size_t           size_per_head,
119	                    size_t           inter_size,
120	                    size_t           num_layer,
121	                    cudaStream_t     stream,
122	                    cublasMMWrapper* cublas_wrapper,
123	                    IAllocator*      allocator,
124	                    bool             is_free_buffer_after_forward):
125	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward),
126	    max_batch_size_(max_batch_size),
127	    head_num_(head_num),
128	    size_per_head_(size_per_head),
129	    inter_size_(inter_size),
130	    num_layer_(num_layer),
131	    hidden_units_(head_num_ * size_per_head)
132	{
133	    initialize();
134	}
135	
136	template<typename T>
137	Decoder<T>::Decoder(Decoder<T> const& decoder):
138	    BaseLayer(decoder.stream_, decoder.cublas_wrapper_, decoder.allocator_, decoder.is_free_buffer_after_forward_),
139	    max_batch_size_(decoder.max_batch_size_),
140	    head_num_(decoder.head_num_),
141	    size_per_head_(decoder.size_per_head_),
142	    inter_size_(decoder.inter_size_),
143	    num_layer_(decoder.num_layer_),
144	    hidden_units_(decoder.hidden_units_)
145	{
146	    initialize();
147	}
148	
149	template<typename T>
150	Decoder<T>::~Decoder()
151	{
152	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
153	    delete self_attention_layer_;
154	    delete cross_attention_layer_;
155	    delete ffn_layer_;
156	    freeBuffer();
157	}
158	
159	template<typename T>
160	void Decoder<T>::forward(std::vector<Tensor>*                      output_tensors,
161	                         const std::vector<Tensor>*                input_tensors,
162	                         const std::vector<DecoderLayerWeight<T>>* decoder_layer_weight)
163	{
164	    // input tensors:
165	    //      decoder_input [batch_size, hidden_dimension],
166	    //      encoder_output [batch_size, mem_max_seq_len, memory_hidden_dimension],
167	    //      encoder_sequence_length [batch_size],
168	    //      finished [batch_size],
169	    //      step [1] on cpu
170	    //      sequence_lengths [batch_size]
171	    //      cache_indirection [local_batch_size / beam_width, beam_width, max_seq_len]
172	    //              Here, local_batch_size contains the beam_width, so local_batch_size / beam_width
173	    //              is real local_batch_size.
174	
175	    // output tensors:
176	    //      decoder_output [batch_size, hidden_dimension],
177	    //      key_cache [num_layer, batch, head_num, size_per_head // x, max_seq_len, x]
178	    //      value_cache [num_layer, batch, head_num, max_seq_len, size_per_head]
179	    //      key_mem_cache [num_layer, batch_size, mem_max_seq_len, hidden_dimension],
180	    //      value_mem_cache [num_layer, batch_size, mem_max_seq_len, hidden_dimension]
181	
182	    FT_CHECK(input_tensors->size() == 7);
183	    FT_CHECK(output_tensors->size() == 5);
184	    isValidBatchSize(input_tensors->at(0).shape[0]);
185	    allocateBuffer(input_tensors->at(0).shape[0]);
186	
187	    const size_t   batch_size      = (size_t)input_tensors->at(0).shape[0];
188	    const size_t   mem_max_seq_len = (size_t)input_tensors->at(1).shape[1];
189	    const DataType data_type       = getTensorType<T>();
190	
191	    TensorMap cross_attention_input_tensors{
192	        {"input_query", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, normed_self_attn_output_}},
193	        {"encoder_output", input_tensors->at(1)},
194	        {"encoder_sequence_length", input_tensors->at(2)},
195	        {"finished", input_tensors->at(3)},
196	        {"step", input_tensors->at(4)}};
197	    TensorMap self_attention_input_tensors{
198	        {"input_query", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, decoder_normed_input_}},
199	        {"finished", input_tensors->at(3)},
200	        {"sequence_lengths", input_tensors->at(5)},
201	        {"step", input_tensors->at(4)}};
202	
203	    TensorMap ffn_input_tensors(
204	        {{"ffn_input", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, normed_cross_attn_output_}}});
205	
206	    for (uint l = 0; l < num_layer_; l++) {
207	        const T* decoder_input = (const T*)((l == 0) ? input_tensors->at(0).getPtr<const T>() : decoder_layer_output_);
208	        T* decoder_output = (T*)((l == num_layer_ - 1) ? output_tensors->at(0).getPtr<T>() : decoder_layer_output_);
209	
210	        size_t self_key_cache_offset = l;
211	        for (auto t = output_tensors->at(1).shape.begin() + 1; t != output_tensors->at(1).shape.end(); ++t) {
212	            self_key_cache_offset *= (*t);
213	        }
214	        size_t self_value_cache_offset = l;
215	        for (auto t = output_tensors->at(2).shape.begin() + 1; t != output_tensors->at(2).shape.end(); ++t) {
216	            self_value_cache_offset *= (*t);
217	        }
218	        const size_t mem_cache_offset = l * batch_size * mem_max_seq_len * hidden_units_;
219	
220	        invokeGeneralLayerNorm(decoder_normed_input_,
221	                               decoder_input,
222	                               decoder_layer_weight->at(l).pre_layernorm_weights.gamma,
223	                               decoder_layer_weight->at(l).pre_layernorm_weights.beta,
224	                               layernorm_eps_,
225	                               batch_size,
226	                               hidden_units_,
227	                               (float*)nullptr,
228	                               0,
229	                               stream_);
230	        sync_check_cuda_error();
231	
232	        int tmp_0 = 0;
233	
234	        self_attention_input_tensors.insertIfValid("cache_indirection", input_tensors->at(6));
235	        TensorMap self_attention_output_tensors{
236	            {"hidden_features", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, self_attn_output_}},
237	            {"key_cache",
238	             Tensor{MEMORY_GPU,
239	                    data_type,
240	                    std::vector<size_t>(output_tensors->at(1).shape.begin() + 1, output_tensors->at(1).shape.end()),
241	                    output_tensors->at(1).getPtrWithOffset(self_key_cache_offset)}},
242	            {"value_cache",
243	             Tensor{MEMORY_GPU,
244	                    data_type,
245	                    std::vector<size_t>(output_tensors->at(2).shape.begin() + 1, output_tensors->at(2).shape.end()),
246	                    output_tensors->at(2).getPtrWithOffset<T>(self_value_cache_offset)}}};
247	        self_attention_layer_->forward(&self_attention_output_tensors,
248	                                       &self_attention_input_tensors,
249	                                       &decoder_layer_weight->at(l).self_attention_weights);
250	
251	        invokeGeneralAddBiasResidualPreLayerNorm(
252	            self_attn_output_,
253	            normed_self_attn_output_,
254	            self_attn_output_,
255	            decoder_input,
256	            decoder_layer_weight->at(l).self_attn_layernorm_weights.gamma,
257	            decoder_layer_weight->at(l).self_attn_layernorm_weights.beta,
258	            decoder_layer_weight->at(l).self_attention_weights.attention_output_weight.bias,
259	            layernorm_eps_,
260	            batch_size,
261	            hidden_units_,
262	            (float*)nullptr,
263	            (float*)nullptr,
264	            (float*)nullptr,
265	            (float*)nullptr,
266	            0,
267	            stream_);
268	        sync_check_cuda_error();
269	
270	        TensorMap cross_attention_output_tensors{
271	            {"hidden_features", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, cross_attn_output_}},
272	            {"key_cache",
273	             Tensor{MEMORY_GPU,
274	                    data_type,
275	                    std::vector<size_t>(output_tensors->at(3).shape.begin() + 1, output_tensors->at(3).shape.end()),
276	                    output_tensors->at(3).getPtrWithOffset<T>(mem_cache_offset)}},
277	            {"value_cache",
278	             Tensor{MEMORY_GPU,
279	                    data_type,
280	                    std::vector<size_t>(output_tensors->at(4).shape.begin() + 1, output_tensors->at(4).shape.end()),
281	                    output_tensors->at(4).getPtrWithOffset<T>(mem_cache_offset)}}};
282	        cross_attention_layer_->forward(&cross_attention_output_tensors,
283	                                        &cross_attention_input_tensors,
284	                                        &decoder_layer_weight->at(l).cross_attention_weights);
285	
286	        invokeGeneralAddBiasResidualPreLayerNorm(
287	            cross_attn_output_,
288	            normed_cross_attn_output_,
289	            cross_attn_output_,
290	            self_attn_output_,
291	            decoder_layer_weight->at(l).cross_attn_layernorm_weights.gamma,
292	            decoder_layer_weight->at(l).cross_attn_layernorm_weights.beta,
293	            decoder_layer_weight->at(l).cross_attention_weights.attention_output_weight.bias,
294	            layernorm_eps_,
295	            batch_size,
296	            hidden_units_,
297	            (float*)nullptr,
298	            (float*)nullptr,
299	            (float*)nullptr,
300	            (float*)nullptr,
301	            0,
302	            stream_);
303	        sync_check_cuda_error();
304	
305	        TensorMap ffn_output_tensors(
306	            {{"ffn_output", Tensor{MEMORY_GPU, data_type, {batch_size, hidden_units_}, decoder_output}}});
307	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &decoder_layer_weight->at(l).ffn_weights);
308	
309	        invokeAddBiasResidual(decoder_output,
310	                              cross_attn_output_,
311	                              decoder_layer_weight->at(l).ffn_weights.output_weight.bias,
312	                              batch_size,
313	                              hidden_units_,
314	                              stream_);
315	        sync_check_cuda_error();
316	    }
317	
318	    if (is_free_buffer_after_forward_ == true) {
319	        freeBuffer();
320	    }
321	}
322	
323	template class Decoder<float>;
324	template class Decoder<half>;
325	#ifdef ENABLE_BF16
326	template class Decoder<__nv_bfloat16>;
327	#endif
328	
329	}  // namespace fastertransformer

