    DecoderLayerWeight() = default;
    DecoderLayerWeight(const int hidden_units, const int inter_size, const int mem_hidden_units):
        hidden_units_(hidden_units), inter_size_(inter_size), mem_hidden_units_(mem_hidden_units)
