197	template<typename T>
198	void DecoderSelfAttentionLayer<T>::allocateBuffer(size_t batch_size)
199	{
200	    const size_t type_size = int8_mode_ == 2 ? sizeof(int8_t) : sizeof(T);
201	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
202	    qkv_buf_ =
203	        reinterpret_cast<T*>(allocator_->reMalloc(qkv_buf_, type_size * batch_size * 3 * local_hidden_units_, false));
204	    context_buf_ =
205	        reinterpret_cast<T*>(allocator_->reMalloc(context_buf_, type_size * batch_size * local_hidden_units_, false));
206	
207	    if (int8_mode_ == 1) {
208	        // We use max_size for n and k since we reuse buffers for both FCs and want to allocate the max
209	        // possible memory that would be required by any of the individual gemms.
210	        const int max_size    = std::max(d_model_, 3 * local_hidden_units_);
211	        mixed_gemm_ws_bytes_  = weight_only_int8_fc_runner_->getWorkspaceSize(batch_size, max_size, max_size);
212	        mixed_gemm_workspace_ = (char*)allocator_->reMalloc(mixed_gemm_workspace_, mixed_gemm_ws_bytes_, false);
213	    }
214	    else if (int8_mode_ == 2) {
215	        const int max_size   = std::max(d_model_, 3 * local_hidden_units_);
216	        int8_gemm_ws_bytes_  = int8_fc_runner_->getWorkspaceSize(batch_size, max_size, max_size);
217	        int8_gemm_workspace_ = (char*)allocator_->reMalloc(int8_gemm_workspace_, int8_gemm_ws_bytes_, false);
218	    }
219	
220	    is_allocate_buffer_ = true;
221	}
222	
223	template<typename T>
224	void DecoderSelfAttentionLayer<T>::freeBuffer()
225	{
226	    if (is_allocate_buffer_) {
227	        allocator_->free((void**)(&qkv_buf_));
228	        allocator_->free((void**)(&context_buf_));
229	        is_allocate_buffer_ = false;
230	
231	        if (mixed_gemm_workspace_) {
232	            allocator_->free((void**)(&mixed_gemm_workspace_));
233	            mixed_gemm_ws_bytes_ = 0;
234	        }
235	    }
236	}
237	
238	template<typename T>
239	bool DecoderSelfAttentionLayer<T>::isValidBatchSize(size_t batch_size)
240	{
241	    if (batch_size <= max_batch_size_) {
242	        return true;
243	    }
244	    else {
245	        freeBuffer();
246	        max_batch_size_ = batch_size * 1.2;
247	        return true;
248	    }
249	}
