458	template<typename T>
459	void DecoderSelfAttentionLayer<T>::forward(TensorMap*                output_tensors,
460	                                           TensorMap*                input_tensors,
461	                                           const AttentionWeight<T>* attention_weights)
462	{
463	    // input tensors:
464	    //      input_query [batch_size, d_model_],
465	    //      sequence_lengths [batch_size]
466	    //      step [1] on cpu
467	    //      finished [batch_size] (optional)
468	    //      total_padding_tokens [batch_size] (optional)
469	    //      max_input_length [1] on cpu (optional)
470	    //      masked_tokens [batch_size, memory_len], (optional)
471	    //      cache_indirection [batch_size / beam_width, beam_width, memory_max_len] (optional)
472	    //      d_prefix_prompt_lengths [batch_size] (optional)
473	    //      max_prefix_prompt_length [1] on cpu (optional)
474	    //      relative_attention_bias [1, head_num, step, step] or [1, head_num, max_seq_len, max_seq_len] (optional)
475	    //      linear_bias_slopes [head_num] (optional)
476	    //      ia3_tasks [batch_size] (optional)
477	
478	    // output tensors:
479	    //      attention_output [batch_size, d_model_],
480	    //      key_cache [batch, local_head_num, size_per_head // x, memory_max_len, x]
481	    //      value_cache [batch, local_head_num, memory_max_len, size_per_head]
482	
483	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
484	    FT_CHECK(output_tensors->at("key_cache").shape.size() == 5 || output_tensors->at("key_cache").shape.size() == 3);
485	    FT_CHECK(output_tensors->at("value_cache").shape.size() == 4
486	             || output_tensors->at("value_cache").shape.size() == 3);
487	    allocateBuffer(input_tensors->at("input_query").shape[0]);
488	
489	    const T*    attention_input         = input_tensors->getPtr<T>("input_query");
490	    const int*  sequence_lengths        = input_tensors->getPtr<int>("sequence_lengths");
491	    const bool* finished                = input_tensors->getPtr<bool>("finished", nullptr);
492	    const bool* masked_tokens           = input_tensors->getPtr<bool>("masked_tokens", nullptr);
493	    const int*  cache_indir             = input_tensors->getPtr<int>("cache_indirection", nullptr);
494	    const T*    relative_attention_bias = input_tensors->getPtr<T>("relative_attention_bias", nullptr);
495	    const int   relative_attention_bias_stride =
496	        input_tensors->isExist("relative_attention_bias") ? input_tensors->at("relative_attention_bias").shape[3] : 0;
497	    const T*   linear_bias_slopes = input_tensors->getPtr<T>("linear_bias_slopes", nullptr);
498	    const bool has_ia3            = input_tensors->isExist("ia3_tasks");
499	
500	    T* attention_out = output_tensors->getPtr<T>("hidden_features");
501	    T* key_cache     = output_tensors->getPtr<T>("key_cache");
502	    T* value_cache   = output_tensors->getPtr<T>("value_cache");
503	
504	    const int batch_size     = input_tensors->at("input_query").shape[0];
505	    const int beam_width     = cache_indir != nullptr ? input_tensors->at("cache_indirection").shape[1] : 1;
506	    const int memory_max_len = output_tensors->at("key_cache").shape[3];
507	
508	    const int* d_prefix_prompt_lengths  = input_tensors->getPtr<int>("d_prefix_prompt_lengths", nullptr);
509	    const int  max_prefix_prompt_length = input_tensors->getVal<int>("max_prefix_prompt_length", 0);
510	
511	    const int m_padded = 8 * div_up(batch_size, 8);
512	#ifdef SPARSITY_ENABLED
513	    bool use_sparse_gemm = sparse_ && cublas_wrapper_->isUseSparse(1, 3 * local_hidden_units_, m_padded, d_model_);
514	#else
515	    constexpr bool use_sparse_gemm = false;
516	#endif
517	
518	    PUSH_RANGE("qkv_gemm");
519	    if (use_sparse_gemm) {
520	#ifdef SPARSITY_ENABLED
521	        cublas_wrapper_->SpGemm(CUBLAS_OP_N,
522	                                CUBLAS_OP_N,
523	                                3 * local_hidden_units_,
524	                                m_padded,
525	                                d_model_,
526	                                attention_weights->query_weight.sp_kernel,
527	                                attention_input,
528	                                qkv_buf_);
529	#endif
530	    }
531	    else {
532	        if (int8_mode_ == 1) {
533	            FT_CHECK(weight_only_int8_fc_runner_.get() != NULL && attention_weights->query_weight.int8_kernel != NULL
534	                     && attention_weights->query_weight.weight_only_quant_scale != NULL);
535	
536	            weight_only_int8_fc_runner_->gemm(
537	                attention_input,
538	                reinterpret_cast<const uint8_t*>(attention_weights->query_weight.int8_kernel),
539	                attention_weights->query_weight.weight_only_quant_scale,
540	                qkv_buf_,
541	                batch_size,
542	                3 * local_hidden_units_,
543	                d_model_,
544	                mixed_gemm_workspace_,
545	                mixed_gemm_ws_bytes_,
546	                stream_);
547	        }
548	        else if (int8_mode_ == 2) {
549	            // Here, we set per_column_scaling to be true because q, k, v may
550	            // use different scales. So, we pass a pointer with shape [3, local_hidden_units_] like
551	            // [s_q, s_q, ..., s_q, s_k, s_k, ..., s_k, s_v, s_v, ..., s_v],
552	            // where s_q are scales of q, s_k are scales of k and s_v are scales of v.
553	            cublas_wrapper_->Int8Gemm(3 * local_hidden_units_,
554	                                      batch_size,
555	                                      d_model_,
556	                                      attention_weights->query_weight.int8_kernel,
557	                                      d_model_,
558	                                      input_tensors->getPtr<int8_t>("input_query"),
559	                                      d_model_,
560	                                      reinterpret_cast<int8_t*>(qkv_buf_),
561	                                      3 * local_hidden_units_,
562	                                      attention_weights->query_weight.scale_inter,
563	                                      true);
564	        }
565	        else {
566	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
567	                                  CUBLAS_OP_N,
568	                                  3 * local_hidden_units_,  // n
569	                                  batch_size,
570	                                  d_model_,  // k
571	                                  attention_weights->query_weight.kernel,
572	                                  3 * local_hidden_units_,  // n
573	                                  attention_input,
574	                                  d_model_,  // k
575	                                  qkv_buf_,
576	                                  3 * local_hidden_units_ /* n */);
577	        }
578	    }
579	    sync_check_cuda_error();
580	    POP_RANGE;
581	    fusedQKV_masked_attention_dispatch<T>(
582	        qkv_buf_,
583	        attention_weights->query_weight.bias,
584	        relative_attention_bias,
585	        key_cache,
586	        value_cache,
587	        cache_indir,
588	        context_buf_,
589	        finished,
590	        sequence_lengths,  // NOTE: current seq len including padding (fixed after meeting the finished id)
591	        batch_size,
592	        batch_size,
593	        beam_width,
594	        local_head_num_,
595	        size_per_head_,
596	        rotary_embedding_dim_,
597	        neox_rotary_style_,
598	        memory_max_len,
599	        d_prefix_prompt_lengths,
600	        max_prefix_prompt_length,
601	        input_tensors->getVal<int>("max_input_length", 0),
602	        input_tensors->getPtr<int>("total_padding_tokens", nullptr),
603	        input_tensors->getVal<int>("step"),
604	        q_scaling_,
605	        relative_attention_bias_stride,
606	        linear_bias_slopes,
607	        masked_tokens,
608	        input_tensors->getPtr<int>("ia3_tasks", nullptr),
609	        has_ia3 ? attention_weights->ia3_key_weight.kernel : nullptr,
610	        has_ia3 ? attention_weights->ia3_value_weight.kernel : nullptr,
611	        int8_mode_ == 2 ? attention_weights->query_weight.scale_out : nullptr,
612	        int8_mode_ == 2 ? attention_weights->attention_output_weight.scale : nullptr,
613	        int8_mode_,
614	        stream_);
615	    sync_check_cuda_error();
616	
617	    PUSH_RANGE("proj gemm");
618	#ifdef SPARSITY_ENABLED
619	    use_sparse_gemm = sparse_ && cublas_wrapper_->isUseSparse(1, d_model_, m_padded, local_hidden_units_);
620	#endif
621	
622	    if (use_sparse_gemm) {
623	#ifdef SPARSITY_ENABLED
624	        cublas_wrapper_->SpGemm(CUBLAS_OP_N,
625	                                CUBLAS_OP_N,
626	                                d_model_,
627	                                m_padded,
628	                                local_hidden_units_,
629	                                attention_weights->attention_output_weight.sp_kernel,
630	                                context_buf_,
631	                                attention_out);
632	#endif
633	    }
634	    else {
635	        if (int8_mode_ == 1) {
636	            FT_CHECK(weight_only_int8_fc_runner_.get() != NULL
637	                     && attention_weights->attention_output_weight.int8_kernel != NULL
638	                     && attention_weights->attention_output_weight.weight_only_quant_scale != NULL);
639	
640	            weight_only_int8_fc_runner_->gemm(
641	                context_buf_,
642	                reinterpret_cast<const uint8_t*>(attention_weights->attention_output_weight.int8_kernel),
643	                attention_weights->attention_output_weight.weight_only_quant_scale,
644	                attention_out,
645	                batch_size,
646	                d_model_,
647	                local_hidden_units_,
648	                mixed_gemm_workspace_,
649	                mixed_gemm_ws_bytes_,
650	                stream_);
651	        }
652	        else if (int8_mode_ == 2) {
653	            int8_fc_runner_->gemm(reinterpret_cast<int8_t*>(context_buf_),
654	                                  attention_weights->attention_output_weight.int8_kernel,
655	                                  QuantMode::PerTensorQuant,
656	                                  attention_weights->attention_output_weight.scale_inter,
657	                                  attention_weights->attention_output_weight.scale_out,
658	                                  output_tensors->getPtr<T>("hidden_features"),
659	                                  batch_size,
660	                                  d_model_,
661	                                  local_hidden_units_,
662	                                  nullptr,
663	                                  0,
664	                                  stream_);
665	        }
666	        else {
667	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
668	                                  CUBLAS_OP_N,
669	                                  d_model_,  // n
670	                                  batch_size,
671	                                  local_hidden_units_,  // k
672	                                  attention_weights->attention_output_weight.kernel,
673	                                  d_model_,  // n
674	                                  context_buf_,
675	                                  local_hidden_units_,  // k
676	                                  attention_out,
677	                                  d_model_ /* n */);
678	        }
679	        sync_check_cuda_error();
680	    }
681	    POP_RANGE;
682	
683	    if (is_free_buffer_after_forward_) {
684	        freeBuffer();
685	    }
686	}
687	
688	template class DecoderSelfAttentionLayer<float>;
689	template class DecoderSelfAttentionLayer<half>;
690	#ifdef ENABLE_BF16
691	template class DecoderSelfAttentionLayer<__nv_bfloat16>;
692	#endif
693	
694	}  // namespace fastertransformer
