72	{
73	    if (finished != nullptr && finished[blockIdx.x / head_num] == true) {
74	        return;
75	    }
76	    int tid     = threadIdx.x;
77	    int bid     = blockIdx.x / head_num;
78	    int head_id = blockIdx.x % head_num;
79	
80	    const bool do_ia3   = step == 1 && ia3_tasks != nullptr;
81	    const int  ia3_task = do_ia3 ? ia3_tasks[bid] : 0;
82	
83	    extern __shared__ __align__(sizeof(float)) unsigned s_buf[];  // align on largest type
84	    T*                                                  sq     = reinterpret_cast<T*>(s_buf);
85	    T*                                                  logits = reinterpret_cast<T*>(&sq[size_per_head]);
86	
87	    int length = __ldg(&length_per_sample[bid]);
88	
89	    int qkv_id      = bid * head_num * size_per_head + head_id * size_per_head + tid;
90	    int qkv_bias_id = head_id * size_per_head + tid;
91	
92	    if (tid < size_per_head) {
93	        sq[tid] = add(query_buf[qkv_id], Q_bias[qkv_bias_id]);
94	    }
95	    __syncthreads();
96	
97	    for (int ite = 0; ite < length; ++ite) {
98	        int key_id = bid * (seq_len * head_num * size_per_head) + ite * (head_num * size_per_head)
99	                     + head_id * size_per_head + tid;
100	
101	        T key = tid < size_per_head ? key_cache[key_id] : (T)(0.0f);
102	
103	        // For the first step, we should add bias to key memory cache.
104	        // The KV memory cache only need to be updated at the first step.
105	        if (step == 1 && tid < size_per_head) {
106	            key = add(key, K_bias[head_id * size_per_head + tid]);
107	            if (do_ia3) {
108	                key = mmha::mul<T, T, T>(key, ia3_key_weights[(ia3_task * head_num + head_id) * size_per_head + tid]);
109	            }
110	            key_cache[key_id] = key;
111	        }
112	
113	        T val = (tid < size_per_head) ? mul(key, sq[tid], scalar) : (T)(0.0f);
114	        T qk  = blockReduceSum(val);
115	        if (threadIdx.x == 0) {
116	            logits[ite] = qk;
117	        }
118	        __syncthreads();  // try to remove
119	    }
120	    __syncthreads();
121	
122	    __shared__ float s_max_val, s_sum;
123	
124	    float local_i = tid < length ? (float)logits[tid] : -1e20f;
125	    float max_val = blockReduceMax(local_i);
126	    if (tid == 0) {
127	        s_max_val = max_val;
128	    }
129	    __syncthreads();
130	
131	    local_i -= s_max_val;
132	    float local_o = tid < length ? __expf(local_i) : 0.0f;
133	    float val     = blockReduceSum(local_o);
134	
135	    if (tid == 0) {
136	        s_sum = val + 1e-6;
137	    }
138	    __syncthreads();
139	    if (tid < length) {
140	        logits[tid] = local_o / s_sum;
141	    }
142	    __syncthreads();
143	
144	    if (tid < size_per_head) {
145	        T sum = (T)0.0f;
146	        for (int ite = 0; ite < length; ++ite) {
147	            int value_id = bid * seq_len * head_num * size_per_head + ite * head_num * size_per_head
148	                           + head_id * size_per_head + tid;
149	
150	            T value = value_cache[value_id];
151	
152	            // for the first step, we should add bias to key memory cache
153	            if (step == 1) {
154	                value = add(value, V_bias[head_id * size_per_head + tid]);
155	                if (do_ia3) {
156	                    value = mmha::mul<T, T, T>(
157	                        value, ia3_value_weights[(ia3_task * head_num + head_id) * size_per_head + tid]);
158	                }
159	                value_cache[value_id] = value;
160	            }
161	            sum = fma(value, logits[ite], sum);
162	        }
163	        context_buf[bid * head_num * size_per_head + head_id * size_per_head + tid] = sum;
164	    }
165	}
