167	template<typename T, int size_per_head, int block_sz>
168	__global__ void cross_attention_kernel_opt(T* __restrict query_buf,
169	                                           const T* __restrict Q_bias,
170	                                           T* __restrict key_cache,
171	                                           const T* __restrict K_bias,
172	                                           T* __restrict value_cache,
173	                                           const T* __restrict V_bias,
174	                                           const int* length_per_sample,
175	                                           T* __restrict context_buf,
176	                                           const bool* finished,
177	                                           int         batch_size,
178	                                           int         head_num,
179	                                           const int   step,
180	                                           const int   seq_len,
181	                                           const float scalar,
182	                                           const int*  ia3_tasks,
183	                                           const T*    ia3_key_weights,
184	                                           const T*    ia3_value_weights)
185	{
186	    if (finished != nullptr && finished[blockIdx.x / head_num] == true) {
187	        return;
188	    }
189	    typedef Copy_t<T, size_per_head> copy_t;
190	    const int                        elems_per_thread = size_per_head / WARP_SIZE;
191	    union Access_t {
192	        copy_t v;
193	        T      x[elems_per_thread];  // supported size 1,2,4
194	    };
195	    typedef struct Float_n_t {
196	        float x[elems_per_thread];  // supported size 1,2,4
197	    } float_n_t;
198	
199	    __shared__ float_n_t    sq[block_sz];
200	    extern __shared__ float logits[];  // use to store the logits from [0~step]
201	
202	    const int warp_id  = threadIdx.x / WARP_SIZE;
203	    const int warp_num = block_sz / WARP_SIZE;
204	
205	    typedef cub::BlockReduce<float, block_sz>          MaxValBlockReduce;
206	    typedef cub::BlockReduce<float, block_sz>          BlockReduce;
207	    __shared__ typename MaxValBlockReduce::TempStorage max_val_block_temp_storage;
208	    __shared__ typename BlockReduce::TempStorage       block_temp_storage;
209	
210	    __shared__ typename cub::WarpReduce<float>::TempStorage temp_storage[warp_num];
211	
212	    const int tid     = threadIdx.x;
213	    const int bid     = blockIdx.x / head_num;
214	    const int head_id = blockIdx.x % head_num;
215	
216	    int length = __ldg(&length_per_sample[bid]);
217	
218	    const int lane_id = tid % WARP_SIZE;
219	
220	    int qkv_id      = bid * head_num * size_per_head + head_id * size_per_head;
221	    int qkv_bias_id = head_id * size_per_head;
222	
223	    int key_value_id = bid * (seq_len * head_num * size_per_head) + +head_id * size_per_head;
224	
225	    const bool do_ia3   = step == 1 && ia3_tasks != nullptr;
226	    const int  ia3_task = do_ia3 ? ia3_tasks[bid] : 0;
227	
228	    query_buf   = &query_buf[qkv_id];
229	    K_bias      = &K_bias[qkv_bias_id];
230	    key_cache   = &key_cache[key_value_id];
231	    Q_bias      = &Q_bias[qkv_bias_id];
232	    V_bias      = &V_bias[qkv_bias_id];
233	    value_cache = &value_cache[key_value_id];
234	    context_buf = &context_buf[qkv_id];
235	
236	    Access_t bias_r, key_val_r, query_buf_r;
237	
238	    // each warp will have its own copy of sq
239	    query_buf_r.v = *((copy_t*)query_buf + lane_id);
240	    bias_r.v      = *((copy_t*)Q_bias + lane_id);
241	    float qb_r[elems_per_thread];
242	    for (int i = 0; i < elems_per_thread; ++i) {
243	        qb_r[i] = (float)query_buf_r.x[i] + (float)bias_r.x[i];
244	    }
245	
246	    // offset for each step
247	    int offset = head_num * size_per_head;
248	
249	    bias_r.v = *((copy_t*)K_bias + lane_id);
250	    for (int ite = warp_id; ite < length; ite += warp_num) {
251	        key_val_r.v = *((copy_t*)&key_cache[ite * offset] + lane_id);
252	
253	        // For the first step, we should add bias to key memory cache.
254	        // The KV memory cache only need to be updated at the first step.
255	        if (step == 1) {
256	            for (int i = 0; i < elems_per_thread; i++) {
257	                key_val_r.x[i] = (float)key_val_r.x[i] + (float)bias_r.x[i];
258	                if (do_ia3) {
259	                    key_val_r.x[i] = (float)key_val_r.x[i]
260	                                     * (float)(ia3_key_weights[(ia3_task * head_num + head_id) * size_per_head + tid]);
261	                }
262	            }
263	            *((copy_t*)&key_cache[ite * offset] + lane_id) = key_val_r.v;
264	        }
265	        float val = 0.f;
266	        for (int i = 0; i < elems_per_thread; i++) {
267	            val = val + (float)key_val_r.x[i] * qb_r[i] * scalar;
268	        }
269	        float qk = cub::WarpReduce<float>(temp_storage[warp_id]).Sum(val);
270	        if (lane_id == 0) {
271	            logits[ite] = qk;
272	        }
273	    }
274	    __syncthreads();
275	
276	    __shared__ float s_max_val, s_sum;
277	    float            local_i = -1e20f;
278	    for (int i = tid; i < length; i += blockDim.x) {
279	        local_i = max(local_i, logits[i]);
280	    }
281	
282	    float max_val = MaxValBlockReduce(max_val_block_temp_storage).Reduce(local_i, cub::Max());
283	    if (tid == 0) {
284	        s_max_val = max_val;
285	    }
286	    __syncthreads();
287	
288	    float local_o = 0.0f;
289	    for (int i = tid; i < length; i += blockDim.x) {
290	        logits[i] = __expf(logits[i] - s_max_val);
291	        local_o += logits[i];
292	    }
293	    float val = BlockReduce(block_temp_storage).Sum(local_o);
294	
295	    if (tid == 0) {
296	        s_sum = val + 1e-6;
297	    }
298	    __syncthreads();
299	
300	    float s_sum_inverse = __fdividef(1.0f, s_sum);
301	    for (int i = tid; i < length; i += blockDim.x) {
302	        logits[i] = logits[i] * s_sum_inverse;
303	    }
304	    __syncthreads();
305	
306	    // This optimization introduces discrepancy because of different order in FP32 summation
307	    float sum_r[elems_per_thread] = {0.f};
308	    bias_r.v                      = *((copy_t*)V_bias + lane_id);
309	    for (int ite = warp_id; ite < length; ite += warp_num) {
310	        key_val_r.v = *((copy_t*)&value_cache[ite * offset] + lane_id);
311	
312	        // For the first step, we should add bias to key memory cache.
313	        if (step == 1) {
314	            for (int i = 0; i < elems_per_thread; i++) {
315	                key_val_r.x[i] = (float)key_val_r.x[i] + (float)bias_r.x[i];
316	                if (do_ia3) {
317	                    key_val_r.x[i] =
318	                        (float)key_val_r.x[i]
319	                        * (float)(ia3_value_weights[(ia3_task * head_num + head_id) * size_per_head + tid]);
320	                }
321	            }
322	            *((copy_t*)&value_cache[ite * offset] + lane_id) = key_val_r.v;
323	        }
324	        for (int i = 0; i < elems_per_thread; ++i) {
325	            sum_r[i] += (float)key_val_r.x[i] * logits[ite];
326	        }
327	    }
328	    for (int i = 0; i < elems_per_thread; i++) {
329	        sq[warp_id * WARP_SIZE + lane_id].x[i] = sum_r[i];
330	    }
331	    __syncthreads();
332	    if (threadIdx.x < WARP_SIZE) {
333	#pragma unroll
334	        for (int j = 1; j < warp_num; j++) {
335	            for (int i = 0; i < elems_per_thread; ++i) {
336	                sum_r[i] = sum_r[i] + (float)sq[j * WARP_SIZE + threadIdx.x].x[i];
337	            }
338	        }
339	    }
340	    __syncthreads();
341	#pragma unroll
342	    for (int i = 0; i < elems_per_thread; i++) {
343	        key_val_r.x[i] = sum_r[i];
344	    }
345	    if (threadIdx.x < WARP_SIZE) {
346	        *((copy_t*)context_buf + lane_id) = key_val_r.v;
347	    }
348	}
