360	template<typename T>
361	void cross_attention_dispatch(T*                               query_buf,
362	                              const T*                         Q_bias,
363	                              T*                               key_cache,
364	                              const T*                         K_bias,
365	                              T*                               value_cache,
366	                              const T*                         V_bias,
367	                              const int*                       length,
368	                              T*                               context_buf,
369	                              const bool*                      finished,
370	                              const int                        max_batch_size,
371	                              const int                        inference_batch_size,
372	                              const int                        head_num,
373	                              const int                        size_per_head,
374	                              const int                        step,
375	                              const int                        memory_max_len,
376	                              const bool                       batch_major_cache,
377	                              const float                      q_scaling,
378	                              outputCrossAttentionParam<float> output_cross_attention_params,
379	                              const int*                       ia3_tasks,
380	                              const T*                         ia3_key_weights,
381	                              const T*                         ia3_value_weights,
382	                              cudaStream_t                     stream)
383	{
384	    if (!batch_major_cache) {
385	        const int block_sz = ATTENTION_BLOCK_SIZE;
386	        float     scalar   = 1.f / (sqrtf(size_per_head * 1.0f) * q_scaling);
387	
388	        dim3 grid(inference_batch_size * head_num);
389	
390	        int cond = size_per_head * ((ATTENION_OPT) ? 1 : 0);
391	        switch (cond) {
392	            case 32:
393	                cross_attention_kernel_opt<T, 32, block_sz>
394	                    <<<grid, block_sz, sizeof(float) * memory_max_len, stream>>>(query_buf,
395	                                                                                 Q_bias,
396	                                                                                 key_cache,
397	                                                                                 K_bias,
398	                                                                                 value_cache,
399	                                                                                 V_bias,
400	                                                                                 length,
401	                                                                                 context_buf,
402	                                                                                 finished,
403	                                                                                 max_batch_size,
404	                                                                                 head_num,
405	                                                                                 step,
406	                                                                                 memory_max_len,
407	                                                                                 scalar,
408	                                                                                 ia3_tasks,
409	                                                                                 ia3_key_weights,
410	                                                                                 ia3_value_weights);
411	                break;
412	            case 64:
413	                cross_attention_kernel_opt<T, 64, block_sz>
414	                    <<<grid, block_sz, sizeof(float) * memory_max_len, stream>>>(query_buf,
415	                                                                                 Q_bias,
416	                                                                                 key_cache,
417	                                                                                 K_bias,
418	                                                                                 value_cache,
419	                                                                                 V_bias,
420	                                                                                 length,
421	                                                                                 context_buf,
422	                                                                                 finished,
423	                                                                                 max_batch_size,
424	                                                                                 head_num,
425	                                                                                 step,
426	                                                                                 memory_max_len,
427	                                                                                 scalar,
428	                                                                                 ia3_tasks,
429	                                                                                 ia3_key_weights,
430	                                                                                 ia3_value_weights);
431	                break;
432	            case 128:
433	                cross_attention_kernel_opt<T, 128, block_sz>
434	                    <<<grid, block_sz, sizeof(float) * memory_max_len, stream>>>(query_buf,
435	                                                                                 Q_bias,
436	                                                                                 key_cache,
437	                                                                                 K_bias,
438	                                                                                 value_cache,
439	                                                                                 V_bias,
440	                                                                                 length,
441	                                                                                 context_buf,
442	                                                                                 finished,
443	                                                                                 max_batch_size,
444	                                                                                 head_num,
445	                                                                                 step,
446	                                                                                 memory_max_len,
447	                                                                                 scalar,
448	                                                                                 ia3_tasks,
449	                                                                                 ia3_key_weights,
450	                                                                                 ia3_value_weights);
451	                break;
452	            default:
453	                // default path
454	
455	                int block_size = 128;
456	
457	                if (memory_max_len <= 64) {
458	                    block_size = 64;
459	                }
460	                else if (memory_max_len <= 128 && memory_max_len > size_per_head) {
461	                    block_size = 128;
462	                }
463	                else if (memory_max_len > 128 && memory_max_len <= 256) {
464	                    block_size = 256;
465	                }
466	                else if (memory_max_len > 256 && memory_max_len <= 512) {
467	                    block_size = 512;
468	                }
469	                else {
470	                    block_size = 1024;
471	                }
472	
473	                if (block_size < size_per_head) {
474	                    block_size = size_per_head;
475	                }
476	
477	                assert(block_size <= 1024);
478	                dim3 block(block_size);
479	
480	                int shared_size = sizeof(T) * (size_per_head + memory_max_len);
481	                cross_attention_kernel<T><<<grid, block, shared_size, stream>>>(query_buf,
482	                                                                                Q_bias,
483	                                                                                key_cache,
484	                                                                                K_bias,
485	                                                                                value_cache,
486	                                                                                V_bias,
487	                                                                                length,
488	                                                                                context_buf,
489	                                                                                finished,
490	                                                                                max_batch_size,
491	                                                                                head_num,
492	                                                                                size_per_head,
493	                                                                                step,
494	                                                                                memory_max_len,
495	                                                                                scalar,
496	                                                                                ia3_tasks,
497	                                                                                ia3_key_weights,
498	                                                                                ia3_value_weights);
499	        }
500	    }
501	    else {
502	        assert(step > 0);
503	        // assert(size_per_head == 32 || size_per_head == 64 || size_per_head == 128);
504	        // using DataType = typename std::conditional<sizeof(T) == 4, float, uint16_t>::type;
505	        using DataType = typename CATypeConverter<T>::Type;
506	        // Prepare the parameters.
507	        Cross_multihead_attention_params<DataType> params;
508	        params.q_bias = reinterpret_cast<const DataType*>(Q_bias);
509	        params.k_bias = reinterpret_cast<const DataType*>(K_bias);
510	        params.v_bias = reinterpret_cast<const DataType*>(V_bias);
511	
512	        // Set the output buffer.
513	        params.out = reinterpret_cast<DataType*>(context_buf);
514	
515	        // Set the input buffers.
516	        params.q        = reinterpret_cast<const DataType*>(query_buf);
517	        params.k        = nullptr;
518	        params.v        = nullptr;
519	        params.stride   = 0;
520	        params.finished = const_cast<bool*>(finished);
521	
522	        params.memory_length_per_sample = const_cast<int*>(length);
523	
524	        params.k_cache    = reinterpret_cast<DataType*>(key_cache);
525	        params.v_cache    = reinterpret_cast<DataType*>(value_cache);
526	        params.batch_size = inference_batch_size;
527	        // TODO(bhsueh) We can use batch but not batch * beam_width in k/v cache in cross attention
528	        // because they are same for all beams.
529	        params.beam_width           = 1;  // We don't care the beam_width in cross attention, set to 1 is enough.
530	        params.memory_max_len       = memory_max_len;
531	        params.timestep             = step - 1;
532	        params.num_heads            = head_num;
533	        params.hidden_size_per_head = size_per_head;
534	        params.inv_sqrt_dh          = 1.F / (sqrtf((float)params.hidden_size_per_head) * q_scaling);
535	
536	        // output cross attentions
537	        params.max_decoder_seq_len        = output_cross_attention_params.max_decoder_seq_len;
538	        params.cross_attention_out        = output_cross_attention_params.cross_attention_out;
539	        params.is_return_cross_attentions = output_cross_attention_params.is_return_cross_attentions;
540	
541	        params.ia3_tasks         = ia3_tasks;
542	        params.ia3_key_weights   = reinterpret_cast<const DataType*>(ia3_key_weights);
543	        params.ia3_value_weights = reinterpret_cast<const DataType*>(ia3_value_weights);
544	
545	        cross_multihead_attention(params, stream);
546	    }
547	}
