610	                                       const int                        memory_max_len,
611	                                       const bool                       batch_major_cache,
612	                                       const float                      q_scaling,
613	                                       outputCrossAttentionParam<float> output_cross_attention_params,
614	                                       const int*                       ia3_tasks,
615	                                       const __nv_bfloat16*             ia3_key_weights,
616	                                       const __nv_bfloat16*             ia3_value_weights,
617	                                       cudaStream_t                     stream);
618	#endif
619	
620	// Currently need to transpose at the first step in Cross attention
621	template<typename T>
622	__global__ void transpose_4d_batch_major_mem_k_cache(
623	    T* k_dst, const T* k_src, const int head_num, const int size_per_head, const int max_seq_len)
624	{
625	    // B, L, H, Dh -> B, H, Dh/x, L, x
626	    const int     batch_id = blockIdx.y;
627	    const int     head_id  = blockIdx.z;
628	    constexpr int X_ELEMS  = (sizeof(T) == 4) ? 4 : 8;
629	
630	    auto key_src = reinterpret_cast<const uint4*>(k_src + batch_id * head_num * size_per_head * max_seq_len
631	                                                  + head_id * size_per_head);
632	    auto key_dst = reinterpret_cast<uint4*>(k_dst + batch_id * head_num * size_per_head * max_seq_len
633	                                            + head_id * size_per_head * max_seq_len);
634	
635	    const int out_idx             = blockIdx.x * blockDim.x + threadIdx.x;
636	    int       size_per_head_div_x = size_per_head / X_ELEMS;
637	    if (out_idx >= size_per_head_div_x * max_seq_len) {
638	        return;
639	    }
640	
641	    int       idx            = out_idx;
642	    const int k_seq_len_id   = idx % max_seq_len;
643	    idx                      = (idx - k_seq_len_id) / max_seq_len;
644	    const int k_head_size_id = idx % size_per_head_div_x;
645	
646	    key_dst[out_idx] = key_src[k_seq_len_id * head_num * size_per_head_div_x + k_head_size_id];
647	}
648	
649	template<typename T>
650	__global__ void transpose_4d_batch_major_mem_v_cache(
651	    T* v_dst, const T* v_src, const int head_num, const int size_per_head, const int max_seq_len)
652	{
653	    // B, L, H, Dh -> B, H, L, Dh
654	    const int batch_id = blockIdx.y;
655	    const int head_id  = blockIdx.z;
656	
657	    // 16 byte loads will handle "x" dimension
658	    auto val_src = reinterpret_cast<const uint4*>(v_src + batch_id * head_num * size_per_head * max_seq_len
659	                                                  + head_id * size_per_head);
660	    auto val_dst = reinterpret_cast<uint4*>(v_dst + batch_id * head_num * size_per_head * max_seq_len
661	                                            + head_id * size_per_head * max_seq_len);
662	
663	    // idx is over output dimension L * size_per_head / x for values
664	    const int out_idx = blockIdx.x * blockDim.x + threadIdx.x;
665	
666	    constexpr int X_ELEMS             = (sizeof(T) == 4) ? 4 : 8;
667	    const int     size_per_head_div_x = size_per_head / X_ELEMS;
668	    if (out_idx >= size_per_head_div_x * max_seq_len) {
669	        return;
670	    }
671	
672	    int       idx            = out_idx;
673	    const int v_head_size_id = idx % size_per_head_div_x;
674	    idx                      = (idx - v_head_size_id) / size_per_head_div_x;
675	    const int v_seq_len_id   = idx % max_seq_len;
676	
677	    val_dst[out_idx] = val_src[v_seq_len_id * head_num * size_per_head_div_x + v_head_size_id];
678	}
679	
680	template<typename T>
681	void transpose_4d_batch_major_memory_kernelLauncher(T*           dst,
682	                                                    const T*     src,
683	                                                    const int    local_batch_size,
684	                                                    const int    max_seq_len,
685	                                                    const int    size_per_head,
686	                                                    const int    local_head_num,
687	                                                    const bool   k_cache,
688	                                                    cudaStream_t stream)
689	{
690	    constexpr int block_sz = 128;
691	
692	    constexpr int x    = (sizeof(T) == 4) ? 4 : 8;
693	    int           size = max_seq_len * size_per_head / x;
694	    dim3          grid((size + block_sz - 1) / block_sz, local_batch_size, local_head_num);
695	
696	    if (k_cache) {
697	        transpose_4d_batch_major_mem_k_cache<<<grid, block_sz, 0, stream>>>(
698	            dst, src, local_head_num, size_per_head, max_seq_len);
699	    }
700	    else {
701	        transpose_4d_batch_major_mem_v_cache<<<grid, block_sz, 0, stream>>>(
702	            dst, src, local_head_num, size_per_head, max_seq_len);
703	    }
704	}
