865	template<typename T>
866	void DecoderCrossAttentionLayer<T>::forward(TensorMap*                output_tensors,
867	                                            TensorMap*                input_tensors,
868	                                            const AttentionWeight<T>* attention_weights)
869	{
870	    // input tensors:
871	    //      attention_input [batch_size, d_model],
872	    //      encoder_output [batch_size, mem_max_seq_len, memory_d_model],
873	    //      encoder_sequence_length [batch_size],
874	    //      step [1] on cpu
875	    //      finished [batch_size] (optional)
876	    //      ia3_tasks [batch_size] (optional)
877	
878	    // output tensors:
879	    //      decoder_layer_output [batch_size, d_model],
880	    //      key_mem_cache [batch_size, head_num, size_per_head // x, mem_max_seq_len, x], where x = 16 / sizeof(T)
881	    //      value_mem_cache [batch_size, head_num, mem_max_seq_len, size_per_head]
882	    //      cross_attentions [batch_size, head_num, max_decoder_seq_len, mem_max_seq_len] optional float*
883	    FT_LOG_DEBUG("%s", __PRETTY_FUNCTION__);
884	    allocateBuffer(input_tensors->at("input_query").shape[0], input_tensors->at("encoder_output").shape[1]);
885	
886	    const T*    attention_input        = input_tensors->getPtr<T>("input_query");
887	    Tensor      encoder_output_tensor  = input_tensors->at("encoder_output");
888	    const int*  memory_sequence_length = input_tensors->getPtr<int>("encoder_sequence_length");
889	    const int   step                   = input_tensors->getVal<int>("step");
890	    const bool* finished               = input_tensors->getPtr<bool>("finished", nullptr);
891	    const bool  has_ia3                = input_tensors->isExist("ia3_tasks");
892	
893	    T* attention_out   = output_tensors->getPtr<T>("hidden_features");
894	    T* key_mem_cache   = output_tensors->getPtr<T>("key_cache");
895	    T* value_mem_cache = output_tensors->getPtr<T>("value_cache");
896	
897	    const bool output_cross_attentions = output_tensors->isExist("cross_attentions");
898	    const int  max_decoder_seq_len     = output_cross_attentions ? output_tensors->at("cross_attentions").shape[2] : 0;
899	
900	    const int batch_size      = input_tensors->at("input_query").shape[0];
901	    const int mem_max_seq_len = encoder_output_tensor.shape[1];
902	    cublas_wrapper_->Gemm(CUBLAS_OP_N,
903	                          CUBLAS_OP_N,
904	                          hidden_units_,  // n
905	                          batch_size,
906	                          d_model_,  // k
907	                          attention_weights->query_weight.kernel,
908	                          hidden_units_,  // n
909	                          attention_input,
910	                          d_model_,  // k
911	                          q_buf_,
912	                          hidden_units_ /* n */);
913	
914	    if (step == 1) {
915	        if (is_batch_major_cache_) {
916	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
917	                                  CUBLAS_OP_N,
918	                                  hidden_units_,
919	                                  batch_size * mem_max_seq_len,
920	                                  encoder_output_tensor.shape[2],
921	                                  attention_weights->key_weight.kernel,
922	                                  hidden_units_,
923	                                  encoder_output_tensor.getPtr<T>(),
924	                                  encoder_output_tensor.shape[2],
925	                                  mem_cache_buf_,
926	                                  hidden_units_);
927	            transpose_4d_batch_major_memory_kernelLauncher<T>(
928	                key_mem_cache, mem_cache_buf_, batch_size, mem_max_seq_len, size_per_head_, head_num_, true, stream_);
929	            sync_check_cuda_error();
930	
931	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
932	                                  CUBLAS_OP_N,
933	                                  hidden_units_,
934	                                  batch_size * mem_max_seq_len,
935	                                  encoder_output_tensor.shape[2],
936	                                  attention_weights->value_weight.kernel,
937	                                  hidden_units_,
938	                                  encoder_output_tensor.getPtr<T>(),
939	                                  encoder_output_tensor.shape[2],
940	                                  mem_cache_buf_,
941	                                  hidden_units_);
942	            transpose_4d_batch_major_memory_kernelLauncher<T>(value_mem_cache,
943	                                                              mem_cache_buf_,
944	                                                              batch_size,
945	                                                              mem_max_seq_len,
946	                                                              size_per_head_,
947	                                                              head_num_,
948	                                                              false,
949	                                                              stream_);
950	            sync_check_cuda_error();
951	        }
952	        else {
953	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
954	                                  CUBLAS_OP_N,
955	                                  hidden_units_,
956	                                  batch_size * mem_max_seq_len,
957	                                  encoder_output_tensor.shape[2],
958	                                  attention_weights->key_weight.kernel,
959	                                  hidden_units_,
960	                                  encoder_output_tensor.getPtr<T>(),
961	                                  encoder_output_tensor.shape[2],
962	                                  key_mem_cache,
963	                                  hidden_units_);
964	
965	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
966	                                  CUBLAS_OP_N,
967	                                  hidden_units_,
968	                                  batch_size * mem_max_seq_len,
969	                                  encoder_output_tensor.shape[2],
970	                                  attention_weights->value_weight.kernel,
971	                                  hidden_units_,
972	                                  encoder_output_tensor.getPtr<T>(),
973	                                  encoder_output_tensor.shape[2],
974	                                  value_mem_cache,
975	                                  hidden_units_);
976	        }
977	    }
978	    sync_check_cuda_error();
979	
980	    outputCrossAttentionParam<float> output_attention_param{};
981	    // output cross attentions
982	    if (output_cross_attentions) {
983	        output_attention_param.max_decoder_seq_len        = max_decoder_seq_len;
984	        output_attention_param.cross_attention_out        = output_tensors->at("cross_attentions").getPtr<float>();
985	        output_attention_param.is_return_cross_attentions = true;
986	    }
987	
988	    cross_attention_dispatch<T>(q_buf_,
989	                                attention_weights->query_weight.bias,
990	                                key_mem_cache,
991	                                attention_weights->key_weight.bias,
992	                                value_mem_cache,
993	                                attention_weights->value_weight.bias,
994	                                memory_sequence_length,
995	                                context_buf_,
996	                                finished,
997	                                batch_size,
998	                                batch_size,
999	                                head_num_,
1000	                                size_per_head_,
1001	                                step,
1002	                                mem_max_seq_len,
1003	                                is_batch_major_cache_,
1004	                                q_scaling_,
1005	                                output_attention_param,
1006	                                has_ia3 ? input_tensors->at("ia3_tasks").getPtr<const int>() : nullptr,
1007	                                has_ia3 ? attention_weights->ia3_key_weight.kernel : nullptr,
1008	                                has_ia3 ? attention_weights->ia3_value_weight.kernel : nullptr,
1009	                                stream_);
1010	    sync_check_cuda_error();
1011	    cublas_wrapper_->Gemm(CUBLAS_OP_N,
1012	                          CUBLAS_OP_N,
1013	                          d_model_,  // n
1014	                          batch_size,
1015	                          hidden_units_,  // k
1016	                          attention_weights->attention_output_weight.kernel,
1017	                          d_model_,  // n
1018	                          context_buf_,
1019	                          hidden_units_,  // k
1020	                          attention_out,
1021	                          d_model_ /* n */);
1022	    if (is_free_buffer_after_forward_ == true) {
1023	        freeBuffer();
1024	    }
1025	}
1026	
1027	template class DecoderCrossAttentionLayer<float>;
1028	template class DecoderCrossAttentionLayer<half>;
1029	#ifdef ENABLE_BF16
1030	template class DecoderCrossAttentionLayer<__nv_bfloat16>;
1031	#endif
1032	
1033	}  // namespace fastertransformer
